   808→// It ranks by whether or not the pod's usage exceeds its requests, then by priority, and
   809→// finally by memory usage above requests.
   810→func rankMemoryPressure(pods []*v1.Pod, stats statsFunc) {
   811→	orderedBy(exceedMemoryRequests(stats), priority, memory(stats)).Sort(pods)
   812→}
   813→
   814→// rankPIDPressure orders the input pods by priority in response to PID pressure.
   815→func rankPIDPressure(pods []*v1.Pod, stats statsFunc) {
